def _compare(result, expected, args):
    if not isinstance(result, list) or len(result) != 2:
        return False
    i, j = result
    if not isinstance(i, int) or not isinstance(j, int) or isinstance(i, bool) or isinstance(j, bool):
        return False
    if i == j:
        return False
    nums = args['nums']
    if not (0 <= i < len(nums) and 0 <= j < len(nums)):
        return False
    return nums[i] + nums[j] == args['target']
